// This allows TypeScript to pick up the magic constants that's auto-generated by Forge's Vite
// plugin that tells the Electron app where to look for the Vite-bundled app code (depending on
// whether you're running in development or production).
declare const MAIN_WINDOW_VITE_DEV_SERVER_URL: string;
declare const MAIN_WINDOW_VITE_NAME: string;

type GameId = string | number;

type GameConfigType = {
  name: string;
  url: string;
  id?: GameId;
  cssId?: string;
  backgroundImageUrl?: string;
  backgroundImageLocalUrl?: string;
  backgroundImageFileName?: string;
  backgroundImageUpdatedAt?: string;
};

type AppConfig = {
  games: GameConfig[];
  cachePath?: string;
  autoCacheClear?: boolean;
  customCSS?: string;
  ignoreCertificateErrors?: boolean;
  discordRP?: boolean;
  notificationTimer?: number;
  serverInfoEnabled?: boolean;
  serverInfoOptions?: ServerInfoOptions;
  serverInfoPingRate?: number;
  fullScreenEnabled?: boolean;
  shareSessionWindows?: boolean;
  windowBounds?: WindowBounds;
};

type WindowBounds = {
  x?: number;
  y?: number;
  width: number;
  height: number;
  isMaximized?: boolean;
};

interface ServerInfoOptions {
  statusEnabled?: boolean;
  foundryVersionEnabled?: boolean;
  worldEnabled?: boolean;
  gameSystemEnabled?: boolean;
  gameSystemVersionEnabled?: boolean;
  onlinePlayersEnabled?: boolean;
}

interface ParticleOptions {
  count?: number;
  color?: string;
  alpha?: number;
  speedYMin?: number;
  speedYMax?: number;
  radiusMin?: number;
  radiusMax?: number;
  ampMin?: number;
  ampMax?: number;
}

type ThemeConfig = {
  background: string;
  backgrounds?: string[];
  backgroundColor: string;
  textColor: string;
  fontPrimary?: string;
  fontPrimaryUrl?: string;
  fontPrimaryName?: string;
  fontPrimaryFilePath?: string;
  fontSecondary?: string;
  fontSecondaryUrl?: string;
  fontSecondaryName?: string;
  fontSecondaryFilePath?: string;
  accentColor: string;
  buttonColorAlpha: number;
  buttonColor: string;
  buttonColorHoverAlpha: number;
  buttonColorHover: string;
  baseTheme?: string;
  particlesEnabled?: boolean;
  particleOptions?: ParticleOptions;
};

type UserData = {
  cachePath?: string;
  [index: GameId]: GameUserData;
  app?: AppConfig;
  theme?: ThemeConfig;
  schemaVersion: number;
  lastRunAppVersion: string;
};

type GameUserData = {
  password?: number[];
  user: string;
  adminPassword?: number[];
};
type GameUserDataDecrypted = {
  password?: string;
  user: string;
  adminPassword?: string;
};

type SaveUserData = {
  gameId: GameId;
  password: string;
  user: string;
  adminPassword: string;
};

type WindowData = {
  gameId: GameId;
  autoLogin: boolean;
  selectedServerName?: string;
};

type WindowsData = {
  [index: number]: WindowData;
};

interface ServerStatusData {
  active: boolean;
  version: string;
  world: string;
  system: string;
  systemVersion: string;
  users: number;
  uptime: number;
}
